queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?method_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMethods ?child ; p:hasEpidemiological_Study ?parent . } GROUP BY ?child }
  ?child p:method_name ?method_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Epidemiological_Study } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?method_name WHERE {
  ?epidemiological_study_methods a :Epidemiological_Study_Methods .
  ?methods a :Methods .
  ?epidemiological_study_methods p:hasMethods ?methods .
  ?epidemiological_study a :Epidemiological_Study .
  ?epidemiological_study_methods p:hasEpidemiological_Study ?epidemiological_study .
  ?epidemiological_study p:name ?name .
  ?methods p:method_name ?method_name .
} }
  collective: { SELECT ?method_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMethods ?child ; p:hasEpidemiological_Study ?parent . } GROUP BY ?child }
  ?child p:method_name ?method_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Epidemiological_Study } }
  FILTER(?nf = ?total)
} }
}
